// Script Continued Below
/*jshint esnext: true */
(function executeRule(current, previous /*null when async*/) {
	//Stamp version number onto record during initialization
	tcs = new TaskerCommonScriptingMethods();
	var taskTableName = "x_153465_discovert_route_task_instance";
	var sys_id = current.sys_id;


	// STRY0106824 - Close Request(s) when task assignment changes.
	if(previous.assigned_to){
		//close any open requests from the previous assigned member
		tcs.queryRelated('x_153465_discovert_tasker_requests', 
						[{"parent":sys_id}, {"u_status": "In progress"}, {"u_requested_by": previous.assigned_to}], 
						function(record){
			record.u_request_comments = gs.getMessage('Tasker - This task has been reassigned to a different user');
			record.u_responded = new GlideDateTime();
			record.u_responded_by=gs.getUserID();
			record.u_response = gs.getMessage('Tasker - This task has been reassigned to a different user');
			record.u_status = "Completed";

			record.setWorkflow(false);
			record.update();
		});
	}

	if(current.assigned_to){
		//change all children's task requester
		tcs.queryRelated(taskTableName, [{"parent":sys_id}], function(record){
			// STRY0076596 - when Task has u_wait_for_subtasks_to_finish checked set task owner to parent task owner or originator
			if(record.u_wait_for_subtasks_to_finish){
				record.u_task_requester = current.u_task_requester;
			}else{
				record.u_task_requester = current.assigned_to;
			}
			record.setWorkflow(false);
			record.update();
		});
	} else {
		//change all children's task owner to the originator
		tcs.queryRelated(taskTableName, [{"parent":sys_id}], function(record){
			// STRY0076596 - when Task has u_wait_for_subtasks_to_finish checked set task owner to parent task owner or originator
			if(record.u_wait_for_subtasks_to_finish){
				record.u_task_requester = current.u_task_requester;
			}else{

				// STRY0078378 - if task owner of parent not set, set the owner of the subtask to the originator of the parent
				if (current.u_task_requester){
					record.u_task_requester = current.u_task_requester;
				} else {
					record.u_task_requester = current.originator;
				}
			}
			record.setWorkflow(false);
			record.update();
		});
	}
})(current, previous);
